// تطبيع التركيز عشان نقارن بشكل صح
// مثال: "50mcg/ml" و "50 mcg/ml" يبقوا نفس الشيء
function normalizeStrength(s) {
  if (!s) return '';
  return s.toLowerCase()
    .replace(/\s+/g, '')
    .replace(/,/g, '|')
    .trim();
}

// تقسيم الاسم العلمي لمكونات
function splitIngredients(name) {
  return name.toLowerCase().trim()
    .split(/\s*,\s*/)
    .map(s => s.trim())
    .filter(s => s.length > 1);
}

// البحث بالاسم العلمي فقط (بدون تركيز)
function findByGeneric(ingredients) {
  return HAAD.filter(d => {
    const g = d.g;
    return ingredients.every(ing => g.includes(ing));
  });
}

// التحقق من تطابق التركيز 100%
function strengthMatch(drugStrength, haadStrength) {
  if (!drugStrength || drugStrength === '' || drugStrength === 'null') return true; // لو مش محدد في الوصفة نقبل أي تركيز
  const norm1 = normalizeStrength(drugStrength);
  const norm2 = normalizeStrength(haadStrength);
  if (norm1 === norm2) return true;
  // جرب مطابقة جزئية للتركيزات المتعددة
  const parts1 = norm1.split('|');
  const parts2 = norm2.split('|');
  return parts1.every(p => parts2.some(q => q.includes(p) || p.includes(q)));
}

function search(genericName, strength, insType) {
  const key = {thiqa:'t', basic:'b', abm1:'a1', abm7:'a7'}[insType] || 't';
  const ingredients = splitIngredients(genericName);

  // الخطوة 1: دور بالاسم العلمي
  const byGeneric = findByGeneric(ingredients);

  // الخطوة 2: من النتايج دي، حدد اللي تركيزه مطابق 100%
  const exactMatch = byGeneric.filter(d => strengthMatch(strength, d.s));

  // الخطوة 3: قسّم لمغطى وغير مغطى
  const exactCovered    = exactMatch.filter(d => d[key] === 1);
  const exactNotCovered = exactMatch.filter(d => d[key] === 0);

  // الخطوة 4: لو مفيش exact match — اعرض الأصناف القريبة مع توضيح الفرق
  const similarCovered    = exactMatch.length === 0 ? byGeneric.filter(d => d[key] === 1) : [];
  const similarNotCovered = exactMatch.length === 0 ? byGeneric.filter(d => d[key] === 0) : [];

  return {
    // نتايج مطابقة 100%
    exactCovered:    exactCovered.map(d => ({ package_name: d.p, strength: d.s, form: d.f, generic: d.g_orig })).slice(0,15),
    exactNotCovered: exactNotCovered.map(d => ({ package_name: d.p, strength: d.s, form: d.f, generic: d.g_orig })).slice(0,8),
    // أصناف مشابهة (نفس الاسم العلمي بس تركيز مختلف)
    similarCovered:    similarCovered.map(d => ({ package_name: d.p, strength: d.s, form: d.f, generic: d.g_orig })).slice(0,8),
    similarNotCovered: similarNotCovered.map(d => ({ package_name: d.p, strength: d.s, form: d.f, generic: d.g_orig })).slice(0,5),
    // هل لاقى حاجة أصلاً؟
    foundByGeneric: byGeneric.length > 0,
    foundExact: exactMatch.length > 0,
    prescribedStrength: strength
  };
}

export default async function handler(req, res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, x-api-key, anthropic-version, x-action');

  if (req.method === 'OPTIONS') return res.status(200).end();
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' });

  try {
    const action = req.headers['x-action'];

    if (action === 'search-haad') {
      const { drugs, insurance } = req.body;

      const results = drugs.map(drug => {
        const found = search(
          drug.generic_name,
          drug.strength || '',
          insurance
        );

        return {
          generic_name: drug.generic_name,
          strength: drug.strength || '',
          form: drug.form || '',
          brand_written: drug.brand_written || null,
          // هل فيه تطابق 100%؟
          exact_match: found.foundExact,
          // هل الدواء مغطى؟
          covered: found.exactCovered.length > 0,
          // أصناف مطابقة 100% مغطاة
          covered_options: found.exactCovered,
          // أصناف مطابقة 100% غير مغطاة
          not_covered_options: found.exactNotCovered,
          // أصناف بنفس الاسم العلمي بس تركيز مختلف (مغطاة)
          similar_covered: found.similarCovered,
          // أصناف بنفس الاسم العلمي بس تركيز مختلف (غير مغطاة)
          similar_not_covered: found.similarNotCovered,
          // مش موجود في الشيت خالص
          not_found: !found.foundByGeneric,
          prescribed_strength: found.prescribedStrength
        };
      });

      return res.status(200).json({ results });
    }

    const apiKey = req.headers['x-api-key'];
    if (!apiKey) return res.status(400).json({ error: 'Missing API key' });

    const response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
      },
      body: JSON.stringify(req.body),
    });

    const data = await response.json();
    return res.status(response.ok ? 200 : response.status).json(data);

  } catch (error) {
    return res.status(500).json({ error: error.message });
  }
}
